import torch

def run(seq_len, weight, x):
    y = []
    x2 = x[0]
    for t in range(seq_len):
        window = x2[:, t:t + weight.shape[1]]
        dot = (window * weight).sum(-1)
        y.append(dot * torch.sigmoid(dot))
    return torch.stack(y, dim=-1).unsqueeze(0)
